     1→/**
     2→ * AI Terminal Component
     3→ * Persistent AI assistant with multi-provider chat interface
     4→ *
     5→ * Features:
     6→ * - Multiple AI providers (OpenRouter, Groq, HuggingFace, Mistral, Gemini, OpenAI, Anthropic, xAI)
     7→ * - Provider/model selection
     8→ * - Automatic fallback on errors
     9→ * - Usage tracking
    10→ * - Encrypted API key storage
    11→ */
    12→
    13→import React, { useState, useRef, useEffect } from 'react';
    14→import { useTerminalStore } from '../stores/useTerminalStore';
    15→import { aiTerminalService } from '../services/aiTerminal';
    16→import { createDefaultRouter } from '../services/ai/providerRouter';
    17→import { ProviderSettings } from './ProviderSettings';
    18→import { ModelSelector } from './ModelSelector';
    19→import { UsageTracker } from './UsageTracker';
    20→import { useEscapeKey } from '../hooks/useEscapeKey';
    21→import ReactMarkdown from 'react-markdown';
    22→
    23→export const AITerminal: React.FC = () => {
    24→  const {
    25→    isOpen,
    26→    apiKey, // Legacy Gemini key
    27→    model: _model, // Legacy model (unused)
    28→    activeProvider,
    29→    activeModel,
    30→    providers,
    31→    encryptionPassword,
    32→    isPasswordExpired,
    33→    fallbackEnabled,
    34→    messages,
    35→    isStreaming,
    36→    setOpen,
    37→    setActiveProvider,
    38→    addMessage,
    39→    clearMessages,
    40→    setStreaming,
    41→  } = useTerminalStore();
    42→
    43→  const [input, setInput] = useState('');
    44→  const [streamingContent, setStreamingContent] = useState('');
    45→  const [showProviderSettings, setShowProviderSettings] = useState(false);
    46→  const [showModelSelector, setShowModelSelector] = useState(false);
    47→  const [showUsageTracker, setShowUsageTracker] = useState(false);
    48→  const [fallbackNotification, setFallbackNotification] = useState<string | null>(null);
    49→
    50→  const messagesEndRef = useRef<HTMLDivElement>(null);
    51→  const inputRef = useRef<HTMLTextAreaElement>(null);
    52→
    53→  // Initialize provider router
    54→  const [router] = useState(() => createDefaultRouter((failedProvider, _failedModel, nextProvider, nextModel, reason) => {
    55→    // Fallback notification callback
    56→    setFallbackNotification(
    57→      `⚠️ ${failedProvider} failed: ${reason}. Switched to ${nextProvider} (${nextModel}).`
    58→    );
    59→    setTimeout(() => setFallbackNotification(null), 5000);
    60→  }));
    61→
    62→  // Auto-scroll to bottom when messages change
    63→  useEffect(() => {
    64→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    65→  }, [messages, streamingContent]);
    66→
    67→  // Focus input when terminal opens
    68→  useEffect(() => {
    69→    if (isOpen) {
    70→      inputRef.current?.focus();
    71→    }
    72→  }, [isOpen]);
    73→
    74→  // Initialize AI service with API key (legacy Gemini)
    75→  useEffect(() => {
    76→    if (apiKey) {
    77→      aiTerminalService.setApiKey(apiKey);
    78→    }
    79→  }, [apiKey]);
    80→
    81→  // Configure router with active provider and model
    82→  useEffect(() => {
    83→    router.updateConfig({
    84→      primaryProvider: activeProvider,
    85→      primaryModel: activeModel,
    86→      fallbackEnabled: fallbackEnabled,
    87→    });
    88→  }, [activeProvider, activeModel, fallbackEnabled, router]);
    89→
    90→  // Initialize provider API keys from encrypted storage
    91→  useEffect(() => {
    92→    const initializeApiKeys = async () => {
    93→      if (encryptionPassword && !isPasswordExpired()) {
    94→        const allProviders = router.getAllProviders();
    95→        for (const [providerId, provider] of Object.entries(allProviders)) {
    96→          const providerConfig = providers[providerId];
    97→          if (providerConfig && providerConfig.encryptedApiKey) {
    98→            try {
    99→              const decryptedKey = await useTerminalStore.getState().getProviderApiKey(providerId, encryptionPassword);
   100→              if (decryptedKey) {
   101→                provider.setApiKey(decryptedKey);
   102→              }
   103→            } catch (error) {
   104→              console.error(`Failed to decrypt ${providerId} API key:`, error);
   105→            }
   106→          }
   107→        }
   108→      }
   109→    };
   110→
   111→    initializeApiKeys();
   112→  }, [encryptionPassword, isPasswordExpired, providers, router]);
   113→
   114→  // Handle ESC key with priority 40 (z-40)
   115→  useEscapeKey({ enabled: isOpen, onEscape: () => setOpen(false), priority: 40 });
   116→
   117→  // Keyboard shortcuts
   118→  useEffect(() => {
   119→    const handleKeyDown = (e: KeyboardEvent) => {
   120→      // Cmd/Ctrl + Shift + A to toggle terminal
   121→      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key.toLowerCase() === 'a') {
   122→        e.preventDefault();
   123→        setOpen(!isOpen);
   124→      }
   125→    };
   126→
   127→    document.addEventListener('keydown', handleKeyDown);
   128→    return () => document.removeEventListener('keydown', handleKeyDown);
   129→  }, [isOpen, setOpen]);
   130→
   131→  const handleSubmit = async (e: React.FormEvent) => {
   132→    e.preventDefault();
   133→    if (!input.trim() || isStreaming) return;
   134→
   135→    const userMessage = input.trim();
   136→    setInput('');
   137→
   138→    // Check if any provider is configured
   139→    const configuredProviders = router.getConfiguredProviders();
   140→    if (configuredProviders.length === 0) {
   141→      addMessage({
   142→        role: 'system',
   143→        content: '⚠️ No AI providers configured. Click the ⚙️ Settings button to add API keys.',
   144→      });
   145→      return;
   146→    }
   147→
   148→    // Check if active provider is configured
   149→    const activeProviderObj = router.getProvider(activeProvider);
   150→    if (!activeProviderObj || !activeProviderObj.isConfigured()) {
   151→      addMessage({
   152→        role: 'system',
   153→        content: `⚠️ Provider "${activeProvider}" is not configured. Please add an API key in Settings.`,
   154→      });
   155→      return;
   156→    }
   157→
   158→    // Add user message
   159→    addMessage({
   160→      role: 'user',
   161→      content: userMessage,
   162→    });
   163→
   164→    // Start streaming
   165→    setStreaming(true);
   166→    setStreamingContent('');
   167→
   168→    try {
   169→      // Send message using router (with automatic fallback)
   170→      const response = await router.sendMessage({
   171→        prompt: userMessage,
   172→        conversationHistory: messages.map((msg) => ({
   173→          role: msg.role as 'user' | 'assistant' | 'system',
   174→          content: msg.content,
   175→        })),
   176→        stream: true,
   177→        onChunk: (chunk) => {
   178→          setStreamingContent((prev) => prev + chunk);
   179→        },
   180→      });
   181→
   182→      // Add complete assistant message with provider/model metadata
   183→      addMessage({
   184→        role: 'assistant',
   185→        content: response.content,
   186→        provider: response.provider || activeProvider,
   187→        model: response.model || activeModel,
   188→      });
   189→    } catch (error: any) {
   190→      addMessage({
   191→        role: 'system',
   192→        content: `❌ Error: ${error.message || 'Unknown error occurred'}`,
   193→      });
   194→    } finally {
   195→      setStreaming(false);
   196→      setStreamingContent('');
   197→    }
   198→  };
   199→
   200→  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
   201→    if (e.key === 'Enter' && !e.shiftKey) {
   202→      e.preventDefault();
   203→      handleSubmit(e);
   204→    }
   205→  };
   206→
   207→  if (!isOpen) return null;
   208→
   209→  return (
   210→    <div
   211→      className={`
   212→        fixed top-0 right-0 h-screen
   213→        transition-transform duration-200 ease-in-out
   214→        ${isOpen ? 'translate-x-0' : 'translate-x-full'}
   215→        w-[300px] lg:w-[375px]
   216→        bg-white dark:bg-black
   217→        border-l border-border-light dark:border-border-dark
   218→        shadow-2xl
   219→        z-40
   220→        flex flex-col
   221→      `}
   222→    >
   223→      {/* Header - Terminal Style */}
   224→      <div className="flex items-center justify-between px-4 py-3 bg-black dark:bg-black text-green-400 border-b border-border-light dark:border-border-dark flex-shrink-0">
   225→        <div className="flex items-center gap-2 font-mono text-sm">
   226→          <span>user@neuman-brain:~$</span>
   227→          <span className="text-green-400 text-xs">
   228→            {router.getConfiguredProviders().length > 0
   229→              ? `${activeProvider}/${activeModel}`
   230→              : 'no-provider'}
   231→          </span>
   232→        </div>
   233→
   234→        <div className="flex items-center gap-1">
   235→          {/* Fallback indicator */}
   236→          {fallbackEnabled && router.getConfiguredProviders().length > 1 && (
   237→            <span className="text-xs bg-green-400/20 px-2 py-0.5 rounded font-mono" title="Automatic fallback enabled">
   238→              🔄
   239→            </span>
   240→          )}
   241→
   242→          {/* Usage Tracker */}
   243→          <button
   244→            onClick={() => setShowUsageTracker(!showUsageTracker)}
   245→            className="p-1 hover:bg-green-400/20 rounded transition-colors text-sm"
   246→            title="Usage Statistics"
   247→          >
   248→            📊
   249→          </button>
   250→
   251→          {/* Model Selector */}
   252→          <button
   253→            onClick={() => setShowModelSelector(!showModelSelector)}
   254→            className="p-1 hover:bg-green-400/20 rounded transition-colors text-sm"
   255→            title="Select Model"
   256→          >
   257→            🔀
   258→          </button>
   259→
   260→          {/* Provider Settings */}
   261→          <button
   262→            onClick={() => setShowProviderSettings(true)}
   263→            className="p-1 hover:bg-green-400/20 rounded transition-colors text-sm"
   264→            title="Provider Settings"
   265→          >
   266→            ⚙️
   267→          </button>
   268→
   269→          {/* Close */}
   270→          <button
   271→            onClick={() => setOpen(false)}
   272→            className="p-1 hover:bg-green-400/20 rounded transition-colors text-base"
   273→            title="Close Terminal"
   274→          >
   275→            ✕
   276→          </button>
   277→        </div>
   278→      </div>
   279→
   280→      {/* Chat Content */}
   281→      <div className="flex flex-col flex-1 overflow-hidden">
   282→        {/* Messages */}
   283→        <div className="flex-1 overflow-y-auto p-4 space-y-4">
   284→            {/* Fallback Notification */}
   285→            {fallbackNotification && (
   286→              <div className="mb-4 p-3 bg-yellow-100 dark:bg-yellow-900/30 border border-yellow-400 dark:border-yellow-600 rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary">
   287→                {fallbackNotification}
   288→              </div>
   289→            )}
   290→
   291→            {messages.length === 0 && router.getConfiguredProviders().length === 0 && (
   292→              <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
   293→                <p className="text-lg font-semibold mb-2">Welcome to AI Terminal!</p>
   294→                <p className="text-sm mb-4">
   295→                  Configure AI providers to get started. Choose from 8 providers including free options!
   296→                </p>
   297→                <button
   298→                  onClick={() => setShowProviderSettings(true)}
   299→                  className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-lg transition-colors"
   300→                >
   301→                  ⚙️ Configure Providers
   302→                </button>
   303→                <div className="mt-4 text-xs space-y-1">
   304→                  <p className="font-medium">Free Providers Available:</p>
   305→                  <p>• OpenRouter (Llama 3.3, Gemini 2.0)</p>
   306→                  <p>• Groq (Lightning-fast inference)</p>
   307→                  <p>• HuggingFace (Thousands of models)</p>
   308→                  <p>• Mistral (European AI)</p>
   309→                </div>
   310→              </div>
   311→            )}
   312→
   313→            {messages.length === 0 && router.getConfiguredProviders().length > 0 && (
   314→              <div className="text-center py-12 text-text-light-secondary dark:text-text-dark-secondary">
   315→                <p className="text-lg font-semibold mb-2">AI Terminal Ready</p>
   316→                <p className="text-sm mb-2">
   317→                  Active: <span className="font-medium text-accent-blue">{activeProvider}</span> • {activeModel}
   318→                </p>
   319→                <p className="text-sm">Ask me anything! I can help with:</p>
   320→                <ul className="text-sm mt-2 space-y-1">
   321→                  <li>💬 General questions & conversation</li>
   322→                  <li>💻 Code generation & explanation</li>
   323→                  <li>🔧 Debugging & problem solving</li>
   324→                  <li>📝 Writing & productivity</li>
   325→                  <li>🔄 Automatic fallback if provider fails</li>
   326→                </ul>
   327→              </div>
   328→            )}
   329→
   330→            {messages.map((message) => (
   331→              <div
   332→                key={message.id}
   333→                className={`flex gap-3 ${
   334→                  message.role === 'user' ? 'justify-end' : 'justify-start'
   335→                }`}
   336→              >
   337→                {message.role !== 'user' && (
   338→                  <div className="w-8 h-8 rounded-full bg-gradient-to-r from-accent-blue to-accent-magenta flex items-center justify-center text-white flex-shrink-0">
   339→                    {message.role === 'system' ? '⚠️' : '🤖'}
   340→                  </div>
   341→                )}
   342→
   343→                <div
   344→                  className={`max-w-[80%] rounded-lg px-4 py-2 font-mono ${
   345→                    message.role === 'user'
   346→                      ? 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-white'
   347→                      : message.role === 'system'
   348→                      ? 'bg-yellow-100 dark:bg-yellow-900/30 text-text-light-primary dark:text-text-dark-primary border border-yellow-400 dark:border-yellow-600'
   349→                      : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-orange-600 dark:text-green-400'
   350→                  }`}
   351→                >
   352→                  {message.role === 'assistant' ? (
   353→                    <div className="prose prose-sm dark:prose-invert max-w-none prose-headings:text-orange-600 dark:prose-headings:text-green-400 prose-code:text-orange-600 dark:prose-code:text-green-400">
   354→                      <ReactMarkdown>{message.content}</ReactMarkdown>
   355→                    </div>
   356→                  ) : (
   357→                    <p className="text-sm whitespace-pre-wrap">{message.content}</p>
   358→                  )}
   359→                  <div className="flex items-center gap-2 text-xs opacity-60 mt-1">
   360→                    <span>{new Date(message.timestamp).toLocaleTimeString()}</span>
   361→                    {message.provider && message.model && (
   362→                      <>
   363→                        <span>•</span>
   364→                        <span className="font-medium" title="Provider and model used">
   365→                          {message.provider} • {message.model}
   366→                        </span>
   367→                      </>
   368→                    )}
   369→                  </div>
   370→                </div>
   371→
   372→                {message.role === 'user' && (
   373→                  <div className="w-8 h-8 rounded-full bg-accent-magenta flex items-center justify-center text-white flex-shrink-0">
   374→                    👤
   375→                  </div>
   376→                )}
   377→              </div>
   378→            ))}
   379→
   380→            {/* Streaming message */}
   381→            {isStreaming && streamingContent && (
   382→              <div className="flex gap-3 justify-start">
   383→                <div className="w-8 h-8 rounded-full bg-gradient-to-r from-accent-blue to-accent-magenta flex items-center justify-center text-white flex-shrink-0">
   384→                  🤖
   385→                </div>
   386→                <div className="max-w-[80%] rounded-lg px-4 py-2 font-mono bg-surface-light-elevated dark:bg-surface-dark-elevated text-orange-600 dark:text-green-400">
   387→                  <div className="prose prose-sm dark:prose-invert max-w-none prose-headings:text-orange-600 dark:prose-headings:text-green-400 prose-code:text-orange-600 dark:prose-code:text-green-400">
   388→                    <ReactMarkdown>{streamingContent}</ReactMarkdown>
   389→                  </div>
   390→                  <div className="flex items-center gap-1 text-xs opacity-60 mt-1">
   391→                    <div className="w-1 h-1 bg-current rounded-full animate-pulse" />
   392→                    <div className="w-1 h-1 bg-current rounded-full animate-pulse delay-75" />
   393→                    <div className="w-1 h-1 bg-current rounded-full animate-pulse delay-150" />
   394→                  </div>
   395→                </div>
   396→              </div>
   397→            )}
   398→
   399→            <div ref={messagesEndRef} />
   400→          </div>
   401→
   402→          {/* Input Area */}
   403→          <div className="border-t border-border-light dark:border-border-dark p-3 bg-surface-light dark:bg-black flex-shrink-0">
   404→            <form onSubmit={handleSubmit} className="flex gap-2">
   405→              <textarea
   406→                ref={inputRef}
   407→                value={input}
   408→                onChange={(e) => setInput(e.target.value)}
   409→                onKeyDown={handleKeyDown}
   410→                placeholder={
   411→                  router.getConfiguredProviders().length > 0
   412→                    ? 'user@neuman-brain:~$ _'
   413→                    : 'Configure providers first...'
   414→                }
   415→                disabled={router.getConfiguredProviders().length === 0 || isStreaming}
   416→                className="flex-1 px-3 py-2 rounded-lg font-mono text-sm bg-white dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark text-text-light-primary dark:text-white placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue dark:focus:ring-green-400 focus:border-transparent resize-none"
   417→                rows={1}
   418→              />
   419→              <button
   420→                type="submit"
   421→                disabled={router.getConfiguredProviders().length === 0 || !input.trim() || isStreaming}
   422→                className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover disabled:bg-neutral-300 dark:disabled:bg-neutral-700 text-white rounded-lg font-medium transition-colors disabled:cursor-not-allowed"
   423→              >
   424→                {isStreaming ? '⋯' : '→'}
   425→              </button>
   426→              {messages.length > 0 && (
   427→                <button
   428→                  type="button"
   429→                  onClick={clearMessages}
   430→                  className="px-3 py-2 bg-surface-light-elevated dark:bg-surface-dark hover:bg-neutral-200 dark:hover:bg-neutral-700 text-text-light-primary dark:text-text-dark-primary rounded-lg text-sm transition-colors"
   431→                  title="Clear chat"
   432→                >
   433→                  🗑️
   434→                </button>
   435→              )}
   436→            </form>
   437→          </div>
   438→        </div>
   439→
   440→      {/* Provider Settings Modal */}
   441→      <ProviderSettings
   442→        isOpen={showProviderSettings}
   443→        onClose={() => setShowProviderSettings(false)}
   444→        router={router}
   445→      />
   446→
   447→      {/* Model Selector Sliding Panel */}
   448→      {showModelSelector && (
   449→        <div className="absolute top-12 right-0 w-96 max-h-[400px] bg-white dark:bg-surface-dark-elevated border-l border-border-light dark:border-border-dark shadow-xl overflow-hidden">
   450→          <div className="p-4 border-b border-border-light dark:border-border-dark flex items-center justify-between bg-surface-light dark:bg-surface-dark">
   451→            <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary">
   452→              Select Model
   453→            </h3>
   454→            <button
   455→              onClick={() => setShowModelSelector(false)}
   456→              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark rounded"
   457→            >
   458→              ✕
