import React, { lazy, Suspense, useEffect, useState } from 'react';
import { indexedDBService } from '../services/indexedDB';
import { useWidgetStore } from '../stores/useWidgetStore';
import { WidgetManager } from '../components/WidgetManager';
import { PresetManager } from '../components/PresetManager';
import { BackgroundCustomizer, type BackgroundSettings } from '../components/BackgroundCustomizer';
import { SortableWidget } from '../components/SortableWidget';
// Masonry removed - using CSS Grid for proper column spanning support
import { DndContext, closestCenter, PointerSensor, useSensor, useSensors, DragOverlay } from '@dnd-kit/core';
import type { DragEndEvent, DragStartEvent } from '@dnd-kit/core';
import { SortableContext, verticalListSortingStrategy } from '@dnd-kit/sortable';

// Weather & Map widget
const WeatherMapWidget = lazy(() => import('../widgets/Dashboard/WeatherMapWidget').then(m => ({ default: m.WeatherMapWidget })));

// Lazy load dashboard widgets
const QuoteWidget = lazy(() => import('../widgets/Dashboard/QuoteWidget').then(m => ({ default: m.QuoteWidget })));
const CryptoWidget = lazy(() => import('../widgets/Dashboard/CryptoWidget').then(m => ({ default: m.CryptoWidget })));
const HackerNewsWidget = lazy(() => import('../widgets/Dashboard/HackerNewsWidget').then(m => ({ default: m.HackerNewsWidget })));
