   194→        e.preventDefault();
   195→
   196→        for (const item of imageItems) {
   197→          const file = item.getAsFile();
   198→          if (file) {
   199→            await uploadImage(file);
   200→          }
   201→        }
   202→      }
   203→    };
   204→
   205→    editorElement.addEventListener('dragenter', handleDragEnter);
   206→    editorElement.addEventListener('dragover', handleDragOver);
   207→    editorElement.addEventListener('dragleave', handleDragLeave);
   208→    editorElement.addEventListener('drop', handleDrop);
   209→    editorElement.addEventListener('paste', handlePaste);
   210→
   211→    return () => {
   212→      editorElement.removeEventListener('dragenter', handleDragEnter);
   213→      editorElement.removeEventListener('dragover', handleDragOver);
   214→      editorElement.removeEventListener('dragleave', handleDragLeave);
   215→      editorElement.removeEventListener('drop', handleDrop);
   216→      editorElement.removeEventListener('paste', handlePaste);
   217→    };
   218→  }, [editor, uploadImage]);
   219→
   220→  // Drag overlay
   221→  if (isDragging) {
   222→    return (
   223→      <div className="absolute inset-0 z-50 bg-accent-blue/10 border-2 border-dashed border-accent-blue rounded-lg flex items-center justify-center pointer-events-none">
   224→        <div className="bg-surface-light dark:bg-surface-dark px-6 py-4 rounded-lg shadow-elevated">
   225→          <p className="text-accent-blue text-lg font-semibold">Drop image here</p>
   226→        </div>
   227→      </div>
   228→    );
   229→  }
   230→
   231→  return null;
   232→};
