   238→const SlashCommandPlugin: React.FC = () => {
   239→  const [editor] = useLexicalComposerContext();
   240→  const [showMenu, setShowMenu] = useState(false);
   241→  const [query, setQuery] = useState('');
   242→  const [menuPosition, setMenuPosition] = useState({ top: 0, left: 0 });
   243→
   244→  const commands = [
   245→    { label: 'Heading 1', icon: 'H1', action: () => {
   246→      editor.update(() => {
   247→        const selection = $getSelection();
   248→        if (selection) {
   249→          // Convert to heading - will implement with format commands
