   254→    { label: 'Heading 2', icon: 'H2', action: () => console.log('Heading 2') },
   255→    { label: 'Heading 3', icon: 'H3', action: () => console.log('Heading 3') },
   256→    { label: 'Bullet List', icon: '•', action: () => console.log('Bullet List') },
   257→    { label: 'Numbered List', icon: '1.', action: () => console.log('Numbered List') },
   258→    { label: 'Code Block', icon: '</>', action: () => console.log('Code Block') },
   259→    { label: 'Quote', icon: '"', action: () => console.log('Quote') },
   260→  ];
   261→
   262→  const filteredCommands = commands.filter(cmd =>
   263→    cmd.label.toLowerCase().includes(query.toLowerCase())
   264→  );
   265→
   266→  useEffect(() => {
   267→    return editor.registerUpdateListener(({ editorState }) => {
   268→      editorState.read(() => {
   269→        const selection = $getSelection();
   270→        if (!selection) {
   271→          setShowMenu(false);
   272→          return;
   273→        }
   274→
   275→        const text = selection.getTextContent();
