   542→/**
   543→ * Auto-save Plugin
   544→ * Debounces editor changes and saves to store
   545→ */
   546→const AutoSavePlugin: React.FC<{ noteId: string }> = ({ noteId }) => {
   547→  const [isSaving, setIsSaving] = useState(false);
   548→  const updateNote = useNotesStore((state) => state.updateNote);
   549→
   550→  // Track timeout ID and last saved content to prevent redundant saves
   551→  const timeoutIdRef = useRef<ReturnType<typeof setTimeout> | null>(null);
   552→  const lastContentRef = useRef<string>('');
   553→  const lastTextRef = useRef<string>('');
   554→
   555→  const handleChange = useCallback((editorState: EditorState) => {
   556→    // Extract plain text for search
   557→    editorState.read(() => {
   558→      const root = $getRoot();
   559→      const contentText = root.getTextContent();
   560→      const contentJson = JSON.stringify(editorState.toJSON());
   561→
   562→      // Skip save if content hasn't actually changed
   563→      if (contentJson === lastContentRef.current && contentText === lastTextRef.current) {
   564→        return;
   565→      }
   566→
   567→      // Clear previous timeout to implement proper debouncing
   568→      if (timeoutIdRef.current) {
   569→        clearTimeout(timeoutIdRef.current);
   570→      }
   571→
   572→      // Debounced save
   573→      timeoutIdRef.current = setTimeout(() => {
   574→        setIsSaving(true);
   575→        updateNote(noteId, {
   576→          content: contentJson,
   577→          contentText,
   578→        });
   579→
   580→        // Update refs with saved content
   581→        lastContentRef.current = contentJson;
   582→        lastTextRef.current = contentText;
   583→
   584→        // Reset saving state after a brief delay
   585→        setTimeout(() => setIsSaving(false), 300);
   586→      }, NOTE_CONSTANTS.AUTOSAVE_DEBOUNCE_MS);
   587→    });
   588→  }, [noteId, updateNote]);
   589→
   590→  // Cleanup timeout on unmount
   591→  useEffect(() => {
   592→    return () => {
   593→      if (timeoutIdRef.current) {
   594→        clearTimeout(timeoutIdRef.current);
   595→      }
   596→    };
   597→  }, []);
   598→
   599→  return (
   600→    <>
   601→      <OnChangePlugin onChange={handleChange} />
   602→      {isSaving && (
   603→        <div className="absolute top-2 right-2 text-xs text-text-light-secondary dark:text-text-dark-secondary">
   604→          Saving...
   605→        </div>
   606→      )}
   607→    </>
   608→  );
   609→};
   610→
   611→/**
   612→ * Lexical Editor Configuration
   613→ */
   614→const getEditorConfig = (initialContent?: string) => ({
   615→  namespace: 'NotesEditor',
   616→  editorState: initialContent || null,
   617→  theme: {
   618→    root: 'editor-root',
   619→    paragraph: 'editor-paragraph',
   620→    text: {
   621→      bold: 'font-bold',
   622→      italic: 'italic',
   623→      underline: 'underline',
   624→      strikethrough: 'line-through',
   625→      code: 'font-mono bg-neutral-100 dark:bg-neutral-800 px-1 rounded',
   626→    },
   627→    heading: {
   628→      h1: 'text-4xl font-bold mt-6 mb-4',
   629→      h2: 'text-3xl font-bold mt-5 mb-3',
   630→      h3: 'text-2xl font-bold mt-4 mb-2',
   631→    },
   632→    list: {
   633→      ul: 'list-disc list-inside my-4',
   634→      ol: 'list-decimal list-inside my-4',
   635→      listitem: 'my-1',
   636→    },
   637→    quote: 'border-l-4 border-border-light dark:border-border-dark pl-4 italic my-4',
   638→    code: 'bg-neutral-900 text-neutral-100 p-4 rounded-lg font-mono text-sm my-4 overflow-x-auto',
   639→    link: 'text-primary-cyan hover:underline',
   640→  },
   641→  nodes: [
   642→    HeadingNode,
   643→    QuoteNode,
   644→    ListNode,
   645→    ListItemNode,
   646→    CodeNode,
   647→    CodeHighlightNode,
   648→    LinkNode,
   649→    AutoLinkNode,
   650→    TableNode,
   651→    TableCellNode,
   652→    TableRowNode,
   653→    ImageNode,
   654→  ],
   655→  onError: (error: Error) => {
   656→    console.error('Lexical error:', error);
   657→  },
   658→});
   659→
   660→/**
   661→ * Notes Editor Props
   662→ */
   663→interface NotesEditorProps {
   664→  noteId: string;
   665→}
   666→
   667→/**
   668→ * Notes Editor Component
   669→ */
   670→export const NotesEditor: React.FC<NotesEditorProps> = ({ noteId }) => {
   671→  const note = useNotesStore((state) => state.getNote(noteId));
   672→  const [wordCount, setWordCount] = useState(0);
   673→  const [charCount, setCharCount] = useState(0);
   674→
   675→  // Memoize editor config to prevent Lexical re-initialization
   676→  // Only recreate when noteId changes, not when content changes
   677→  const editorConfig = useMemo(
   678→    () => getEditorConfig(note?.content),
   679→    [noteId] // Key on noteId only, not note.content
   680→  );
   681→
   682→  const handleWordCountUpdate = useCallback((words: number, chars: number) => {
   683→    setWordCount(words);
   684→    setCharCount(chars);
   685→  }, []);
   686→
   687→  if (!note) {
   688→    return (
   689→      <div className="h-full flex items-center justify-center text-text-light-secondary dark:text-text-dark-secondary">
   690→        Note not found
   691→      </div>
   692→    );
   693→  }
   694→
   695→  return (
   696→    <motion.div
   697→      initial={{ opacity: 0 }}
   698→      animate={{ opacity: 1 }}
   699→      transition={{ duration: 0.2 }}
   700→      className="h-full flex flex-col bg-surface-light dark:bg-surface-dark"
   701→    >
   702→      {/* Note Title */}
   703→      <div className="border-b border-border-light dark:border-border-dark px-6 py-4 flex-shrink-0">
   704→        <input
   705→          type="text"
   706→          value={note.title}
   707→          onChange={(e) =>
   708→            useNotesStore.getState().updateNote(noteId, { title: e.target.value })
   709→          }
   710→          placeholder="Untitled Note"
   711→          className="w-full text-3xl font-bold bg-transparent border-none outline-none text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary"
   712→        />
   713→      </div>
   714→
   715→      {/* Lexical Editor */}
   716→      <LexicalComposer key={noteId} initialConfig={editorConfig}>
   717→        <div className="flex-1 flex flex-col relative overflow-hidden shadow-card">
   718→          {/* Toolbar */}
   719→          <div className="flex-shrink-0">
   720→            <EditorToolbar wordCount={wordCount} charCount={charCount} noteId={noteId} />
   721→          </div>
   722→
   723→          {/* Editor Content */}
   724→          <div className="flex-1 overflow-y-auto">
   725→            <div className="max-w-4xl mx-auto px-8 py-6">
   726→              <div className="border border-border-light dark:border-border-dark rounded-lg p-3 min-h-[600px] bg-surface-light dark:bg-surface-dark">
   727→                <RichTextPlugin
   728→                  contentEditable={
   729→                    <ContentEditable className="editor-content outline-none w-full min-h-[600px] text-text-light-primary dark:text-text-dark-primary" />
   730→                  }
   731→                  placeholder={
   732→                    <div className="editor-placeholder absolute top-10 left-12 text-text-light-secondary dark:text-text-dark-secondary pointer-events-none opacity-60">
   733→                      Start writing...
   734→                    </div>
   735→                  }
   736→                  ErrorBoundary={LexicalErrorBoundary}
   737→                />
   738→              <HistoryPlugin />
   739→              <ListPlugin />
   740→              <TablePlugin />
   741→              <MarkdownShortcutPlugin transformers={TRANSFORMERS} />
   742→              <AutoLinkPlugin matchers={MATCHERS} />
   743→              <KeyboardShortcutsPlugin />
   744→              <WordCountPlugin onUpdate={handleWordCountUpdate} />
   745→              <SlashCommandPlugin />
   746→              <ImageUploadPlugin noteId={noteId} />
   747→              <AutoSavePlugin noteId={noteId} />
   748→              </div>
   749→            </div>
   750→          </div>
   751→        </div>
   752→      </LexicalComposer>
   753→    </motion.div>
   754→  );
   755→};
   756→
   757→/**
   758→ * Empty State - No Note Selected
   759→ */
   760→export const NotesEditorEmpty: React.FC = () => {
   761→  return (
   762→    <div className="h-full flex items-center justify-center bg-surface-light-elevated dark:bg-surface-dark">
   763→      <div className="text-center">
   764→        <div className="text-6xl mb-4">📝</div>
   765→        <h2 className="text-2xl font-bold text-text-light-primary dark:text-text-dark-primary mb-2">
   766→          No Note Selected
   767→        </h2>
   768→        <p className="text-text-light-secondary dark:text-text-dark-secondary">
   769→          Select a note from the sidebar or create a new one
   770→        </p>
   771→      </div>
   772→    </div>
